import re
import math
import datetime
import calendar

def transform(row):
    if not row:
        return ''
    input_str = row[0]

    # Example 1: 'san fraccisno' -> 'San Francisco'
    # Example 2: 'SF.' -> 'San Francisco'
    # Example 3: '' -> ''
    # Example 4: 'SAN FRANCISOC' -> 'San Francisco'

    # Clean and split into words
    words = words(input_str)
    if len(words) == 2:
        first = first_word(input_str)
        second = last_word(input_str)
        return f"{alpha(first)} {alpha(second)}"

    # Check for city names
    if re.match(r'^[A-Z][a-z]+$', input_str):
        return alpha(input_str)

    # Check for city abbreviations
    if re.match(r'^[A-Z][a-z]+$', input_str):
        return alpha(input_str)

    # Check for city names with numbers
    if re.match(r'^[A-Z][a-z]+ \d+$', input_str):
        return f"{alpha(first_word(input_str))} {alpha(last_word(input_str))}"

    # Check for city names with periods
    if re.match(r'^[A-Z][a-z]+\.$', input_str):
        return alpha(input_str)

    # Check for city names with numbers and periods
    if re.match(r'^[A-Z][a-z]+ \d+\.$', input_str):
        return f"{alpha(first_word(input_str))} {alpha(last_word(input_str))}"

    # Default case
    return alpha(input_str)
