def transform(row):
    if len(row) == 0:
        return ""
    if len(row) > 1:
        return row[0]
    name = row[0]
    if re.match(r'^[A-Z][a-z]+ [A-Z][a-z]+$', name):
        return first_word(name)
    if re.match(r'^[A-Z][a-z]+ [A-Z][a-z]+ [A-Z][a-z]+$', name):
        return first_word(name)
    if re.match(r'^[A-Z][a-z]+ [A-Z][a-z]+ [A-Z][a-z]+ [A-Z][a-z]+$', name):
        return first_word(name)
    if re.match(r'^[A-Z][a-z]+$', name):
        return name
    return name
